#include<iostream>
using namespace std;
int main()
{
    long long n;
    string a="0123456789ABCDEF";
	cin>>n;
	if(n==0)
    {
        cout<<"00";
        return 0;
    }
	while(n>0)
    {
		int k=n%128;
		n/=128;
		if(n>0)
        {
            cout<<a[(k+128)/16]<<a[(k+128)%16]<<" ";
        }
		else
        { 
            cout<<a[k/16]<<a[k%16]<<" ";
        }
	}
	return 0;
}
